    try:
        ip_address = connect_wifi(WIFI_SSID, WIFI_PASSWORD)
        if ip_address:
            print(f"ESP32 IP Address: {ip_address}")
            ws_server = WebSocketServer(host='0.0.0.0', port=80)
            ws_server.start()
        else:
            print("Failed to connect to WiFi.")
    except KeyboardInterrupt:
        print("Server interrupted by user.")
    finally:
        if 'ws_server' in locals() and ws_server.running:
            ws_server.stop()
        print("Exiting application.")

